package main

import "fmt"

// Index ищет элемент в срезе любого типа
func Index[T comparable](s []T, x T) int {
	for i, v := range s {
		if v == x {
			return i
		}
	}
	return -1
}

func main() {
	numbers := []int{10, 20, 30, 40}
	fmt.Println("Индекс 30:", Index(numbers, 30))

	words := []string{"Go", "is", "awesome"}
	fmt.Println("Индекс \"is\":", Index(words, "is"))
}

