package main

import "fmt"

type List[T comparable] struct {
	next  *List[T]
	value T
}

func (l *List[T]) PushFront(v T) *List[T] {
	return &List[T]{next: l, value: v}
}

func main() {
	var head *List[int]
	head = head.PushFront(3)
	head = head.PushFront(2)
	head = head.PushFront(1)
	fmt.Println("Длина:", head.Len())
}

